import { Injectable, Logger } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";

import { PaymentGatewayLogEntity } from "../payment-gateway-log.entity.ts";

export interface LogRequestParams {
  endpoint: string;
  method: string;
  requestBody?: unknown;
  requestHeaders?: unknown;
  responseBody?: unknown;
  responseStatus?: number;
  errorMessage?: string;
  durationMs?: number;
  requestId?: string;
}

@Injectable()
export class PaymentGatewayLogService {
  private readonly logger = new Logger(PaymentGatewayLogService.name);

  constructor(
    @InjectRepository(PaymentGatewayLogEntity)
    private readonly gatewayLogRepository: Repository<PaymentGatewayLogEntity>,
  ) {}

  async logRequest(params: LogRequestParams): Promise<void> {
    try {
      const logEntry = this.gatewayLogRepository.create({
        endpoint: params.endpoint,
        method: params.method,
        requestBody: params.requestBody
          ? JSON.stringify(params.requestBody)
          : undefined,
        requestHeaders: params.requestHeaders
          ? JSON.stringify(params.requestHeaders)
          : undefined,
        responseBody: params.responseBody
          ? JSON.stringify(params.responseBody)
          : undefined,
        responseStatus: params.responseStatus,
        errorMessage: params.errorMessage,
        durationMs: params.durationMs,
        requestId: params.requestId,
      });

      await this.gatewayLogRepository.save(logEntry);
    } catch (error) {
      // Don't throw error for logging failures, just log the error
      this.logger.error("Failed to log payment gateway request", error);
    }
  }
}
